package ingest

import (
	"fmt"
	"os"
	"path/filepath"
	"strings"

	"github.com/a<HOME>/agentic-rag-mcp/internal/config"
)

// FilterResult captures whether a file passed or was rejected.
type FilterResult struct {
	Allowed bool
	Reason  string
}

// SecurityFilter applies the 4-layer security model to decide whether a file should be indexed.
func SecurityFilter(path string, info os.FileInfo, cfg config.SecurityConfig) FilterResult {
	name := filepath.Base(path)

	// Layer 1: Extension allowlist
	ext := strings.ToLower(filepath.Ext(name))
	allowed := false
	for _, a := range cfg.ExtensionAllowlist {
		if ext == a {
			allowed = true
			break
		}
	}
	if !allowed {
		return FilterResult{Allowed: false, Reason: fmt.Sprintf("extension %q not on allowlist", ext)}
	}

	// Layer 2: Filename blocklist
	lowerName := strings.ToLower(name)
	for _, blocked := range cfg.FilenameBlocklist {
		if lowerName == strings.ToLower(blocked) {
			return FilterResult{Allowed: false, Reason: fmt.Sprintf("filename %q is blocklisted", name)}
		}
	}

	// Layer 3: Directory blocklist
	dir := filepath.Dir(path)
	parts := strings.Split(dir, string(filepath.Separator))
	for _, part := range parts {
		lowerPart := strings.ToLower(part)
		for _, blocked := range cfg.DirectoryBlocklist {
			if lowerPart == strings.ToLower(blocked) {
				return FilterResult{Allowed: false, Reason: fmt.Sprintf("directory %q is blocklisted", part)}
			}
		}
	}

	// Layer 4: Size limit
	if info != nil && info.Size() > cfg.MaxFileSizeBytes {
		return FilterResult{
			Allowed: false,
			Reason:  fmt.Sprintf("file size %d exceeds limit %d", info.Size(), cfg.MaxFileSizeBytes),
		}
	}

	return FilterResult{Allowed: true}
}
